// 暫存腳本：依 topics.json 重建 facts_Topic shards（唯讀 master，僅寫衍生檔）
import fs from 'node:fs';
import path from 'node:path';

const MEM = 'G:/AI/AIMemory';
const USER = '509424983';
const master = fs.readFileSync(path.join(MEM, `facts-${USER}.md`), 'utf8');
// CRLF-safe split（比照 MCP readMasterLines）
const lines = master.split(/\r?\n/).filter(l => l.trim().startsWith('- ['));

const rawTopics = fs.readFileSync(path.join(MEM, 'topics.json'), 'utf8');
const jsonText = rawTopics.split(/\r?\n/).filter(l => !l.trim().startsWith('//')).join('\n');
const topics = JSON.parse(jsonText);

const buckets = new Map(topics.map(t => [t.topic, []]));
buckets.set('misc', []);
for (const line of lines) {
  const lower = line.toLowerCase();
  const hit = topics.find(t => t.keywords.some(k => lower.includes(k)));
  buckets.get(hit ? hit.topic : 'misc').push(line);
}

const shardDir = path.join(MEM, 'facts_Topic', USER);
// 移除不在新 topic 集的舊 shard
const valid = new Set([...buckets.keys()].map(t => `${t}.md`));
for (const f of fs.readdirSync(shardDir)) {
  if (f.endsWith('.md') && !valid.has(f)) {
    fs.unlinkSync(path.join(shardDir, f));
    console.log(`removed stale shard: ${f}`);
  }
}
// 寫入 shards
let total = 0;
for (const [topic, arr] of buckets) {
  fs.writeFileSync(path.join(shardDir, `${topic}.md`), arr.join('\n') + (arr.length ? '\n' : ''), 'utf8');
  console.log(`${topic}: ${arr.length}`);
  total += arr.length;
}
console.log(`total: ${total} / master lines: ${lines.length}`);
if (buckets.get('misc').length) {
  console.log('--- misc contents ---');
  for (const l of buckets.get('misc')) console.log(l.slice(0, 80));
}

