// 暫存腳本：複刻 MCP forget 安全邏輯（CRLF-safe + 空寫保護 + 比例閘門 + 寫前備份）
// 刪除 6 條過時/瑣碎/冗餘 facts，並重建 topic shards
import fs from 'node:fs';
import path from 'node:path';

const MEM = 'G:/AI/AIMemory';
const USER = '509424983';
const masterPath = path.join(MEM, `facts-${USER}.md`);

// 刪除目標：以 fact ID 或獨特 substring 匹配
const targets = [
  'f_b533eb',        // 過時：kiro-cli acp 舊配置，被 f_392c22 取代
  'f_dc72cc',        // 過程性：upstream 同步紀錄，wiki + f_75638b 涵蓋
  'f_6a3827',        // 冗餘：NotebookLM 根因已入 wiki，actionable 由 f_a4464b/f_75638b 承載
  'f_1dbc98',        // 一次性：首次重啟下載 model，重啟後失效
  'f_7366e2',        // 純記錄：Passive Monitor cron，wiki 涵蓋、實況在 schedules.json
  '一律在正本 G:\\AI\\AI-canonical\\skills', // 冗餘 noID fact：skill SOP，steering + wiki 涵蓋
];

// 1. 寫前備份
const bak = `${masterPath}.bak.${Date.now()}`;
fs.copyFileSync(masterPath, bak);
console.log(`backup: ${bak}`);

// 2. CRLF-safe 讀取
const raw = fs.readFileSync(masterPath, 'utf8');
const lines = raw.split(/\r?\n/);
const factLines = lines.filter(l => l.trim().startsWith('- ['));

const removed = [];
const kept = lines.filter(l => {
  if (!l.trim().startsWith('- [')) return true; // 非 fact 行（空行）保留
  const hit = targets.some(t => l.includes(t));
  if (hit) removed.push(l.slice(0, 60));
  return !hit;
});

// 3. 空寫保護 + 比例閘門
const keptFacts = kept.filter(l => l.trim().startsWith('- ['));
if (keptFacts.length === 0) throw new Error('ABORT: kept=0（空寫保護）');
const ratio = removed.length / factLines.length;
if (ratio > 0.5) throw new Error(`ABORT: 刪除比例 ${(ratio * 100).toFixed(1)}% > 50%（比例閘門）`);
if (removed.length !== targets.length) {
  console.warn(`WARN: 預期刪 ${targets.length} 條，實際匹配 ${removed.length} 條`);
}

// 4. 寫回 master
fs.writeFileSync(masterPath, kept.join('\n'), 'utf8');
console.log(`removed ${removed.length}/${factLines.length} facts, kept ${keptFacts.length}`);
for (const r of removed) console.log(`  - ${r}`);

// 5. 重建 shards
const rawTopics = fs.readFileSync(path.join(MEM, 'topics.json'), 'utf8');
const topics = JSON.parse(rawTopics.split(/\r?\n/).filter(l => !l.trim().startsWith('//')).join('\n'));
const buckets = new Map(topics.map(t => [t.topic, []]));
buckets.set('misc', []);
for (const line of keptFacts) {
  const lower = line.toLowerCase();
  const hit = topics.find(t => t.keywords.some(k => lower.includes(k)));
  buckets.get(hit ? hit.topic : 'misc').push(line);
}
const shardDir = path.join(MEM, 'facts_Topic', USER);
for (const [topic, arr] of buckets) {
  fs.writeFileSync(path.join(shardDir, `${topic}.md`), arr.join('\n') + (arr.length ? '\n' : ''), 'utf8');
  console.log(`${topic}: ${arr.length}`);
}

